sql:
SELECT COUNT(*) AS out_of_stock_count
FROM inventory
WHERE status = 'out of stock';

SELECT warehouse_name
FROM warehouses
WHERE capacity = (SELECT MAX(capacity) FROM warehouses);

SELECT cable_model
FROM cables
WHERE length BETWEEN 1.5 AND 2.5;

external_knowledge:
- 'ocean liners' metaphorically refers to 'cable models';
- 'harbors' are metaphorical references to 'warehouses';
- 'anchors' are used metaphorically to signify 'units' or 'quantity';
- 'fleet' is used metaphorically to indicate 'total quantity' of a cable model in a warehouse;
- Longer than 1 meter is a direct condition applied to the length of the cable.

- The 'primary manager' refers to the manager with 'manager_id = 0';
- 'Significant capacity' refers to warehouses with a capacity more than 500;
- 'Well-stocked' implies that the total stock of cables in the warehouse exceeds 1000 units.

sql:
SELECT COUNT(*) AS low_stock_cables
FROM inventory
WHERE quantity < min_stock_level;

external_knowledge:
- 'woven in armor' refers to cables with 'YES' for shielded_type;
- 'bearing the strength to carry more than a two-fold current' refers to max_current > 2.0;
- 'the tallest giants in the forest' refers to ordering by length in descending order.

sql:
SELECT cable_type
FROM cables
WHERE max_current = (SELECT MAX(max_current) FROM cables);
